.loader {color: var(--loader-color, #9333ea);
  --loader-secondary-color: #f0abfc;
  --loader-bg: #ffffff;
   width: 100px;
   height: 50px;
   border-radius: 100px 100px 0 0;
   position: relative;
   overflow: hidden;
}
.loader:before  {
  content: "";
   position: absolute;
   inset: 0 0 -100%;
   background: radial-gradient(farthest-side at top,#0000 35%,var(--loader-secondary-color, #f0abfc),var(--loader-secondary-color, #f0abfc),var(--loader-secondary-color, #f0abfc),var(--loader-secondary-color, #f0abfc),var(--loader-secondary-color, #f0abfc),var(--loader-secondary-color, #f0abfc),var(--loader-secondary-color, #f0abfc),#0000) bottom/100% 50% no-repeat;
   animation: l8 2s infinite;
}
@keyframes l8  {
  0%,20% {transform: rotate(0)}
40%,60% {transform: rotate(.5turn)}
80%,100% {transform: rotate(1turn)}
}
